action.new:
def route(event, rules, default="unrouted"):
    priority = event.get("priority", 0)
    matching_rules = []
    for rule in rules:
        if event.get("kind") == rule["kind"] and priority >= rule.get("min_priority", 0):
            matching_rules.append(rule)

    if not matching_rules:
        return default

    best_rule = None
    best_priority = -1
    for rule in matching_rules:
        rule_priority = rule.get("min_priority", 0)
        if rule_priority > best_priority:
            best_priority = rule_priority
            best_rule = rule

    return best_rule["target"] if best_rule else default

