def allocate(total, weights):
    if total < 0 or not weights or any(value <= 0 for value in weights.values()):
        raise ValueError("invalid total or weights")
    names = list(weights)
    total_weight = sum(weights.values())
    # Calculate exact weighted shares and take floors
    floors = {}
    remainders = {}
    for i, name in enumerate(names):
        share = total * weights[name] / total_weight
        floors[name] = int(share)
        remainders[name] = share - floors[name]
    # Sum of floors
    sum_floors = sum(floors.values())
    # Number of remaining units to distribute
    remainder_units = total - sum_floors
    # Give remaining units to largest fractional remainders (ties follow mapping order)
    sorted_by_remainder = sorted(names, key=lambda n: (-remainders[n], names.index(n)))
    result = dict(floors)
    for i, name in enumerate(sorted_by_remainder):
        if i < remainder_units:
            result[name] += 1
    return result

